mapper.select:
/* ExhibitionMapper.getAdminExhibitionList: 관리자 기획전 목록 조회 */ SELECT EB.EXHIBITION_NO , EB.EXHIBITION_NM , DATE_FORMAT(EB.DISP_START_DT, '%Y-%m-%d %H:%i:%s') AS DISP_START_DT , DATE_FORMAT(EB.DISP_END_DT, '%Y-%m-%d %H:%i:%s') AS DISP_END_DT , EB.LIST_VIEW_YN AS LIST_SHOW_YN , EB.VIEW_YN , EB.THUMBNAIL_URL , DATE_FORMAT(EB.REG_DT, '%Y-%m-%d %H:%i:%s') AS REG_DT , DATE_FORMAT(EB.UDT_DT, '%Y-%m-%d %H:%i:%s') AS UDT_DT FROM EXHIBITION_BASE EB WHERE EB.DEL_YN = 'N'
AND EB.EXHIBITION_NO = #{searchValue}
AND EB.EXHIBITION_NM LIKE CONCAT('%', #{searchValue}, '%')
AND (EB.DISP_END_DT IS NULL OR EB.DISP_END_DT >= #{searchStartDt})
AND (EB.DISP_START_DT IS NULL OR EB.DISP_START_DT <= #{searchEndDt})
ORDER BY EB.LIST_VIEW_YN DESC, EB.DISP_START_DT DESC, EB.EXHIBITION_NO DESC LIMIT #{pageSize} OFFSET #{offset}

/* ExhibitionMapper.getAdminExhibitionCount: 관리자 기획전 목록 건수 조회 */ SELECT COUNT(1) FROM EXHIBITION_BASE EB WHERE EB.DEL_YN = 'N'
AND EB.EXHIBITION_NO = #{searchValue}
AND EB.EXHIBITION_NM LIKE CONCAT('%', #{searchValue}, '%')
AND (EB.DISP_END_DT IS NULL OR EB.DISP_END_DT >= #{searchStartDt})
AND (EB.DISP_START_DT IS NULL OR EB.DISP_START_DT <= #{searchEndDt})

/* ExhibitionMapper.getExhibitionGoodsList: 기획전 탭 상품 목록 조회 */ SELECT ET.EXHIBITION_NO , ETG.EXHIBITION_TAB_NO , ET.EXHIBITION_TAB_NM AS TAB_NM , ETG.GOODS_ID , GB.ERP_STYLE_CD , GB.GOODS_NM , ( SELECT GI.IMG_PATH FROM GOODS_IMG GI WHERE GI.GOODS_ID = ETG.GOODS_ID ORDER BY GI.DISP_ORD ASC, GI.IMG_NO ASC LIMIT 1 ) AS IMG_PATH , ETG.SORT_SEQ AS DISP_ORD , ETG.VIEW_YN AS SHOW_YN , 'N' AS DEL_YN FROM EXHIBITION_TAB_GOODS ETG JOIN EXHIBITION_TAB ET ON ET.EXHIBITION_TAB_NO = ETG.EXHIBITION_TAB_NO AND ET.DEL_YN = 'N' JOIN GOODS_BASE GB ON GB.GOODS_ID = ETG.GOODS_ID WHERE ET.EXHIBITION_NO = #{exhibitionNo}
AND ETG.EXHIBITION_TAB_NO = #{exhibitionTabNo}
ORDER BY ETG.EXHIBITION_TAB_NO ASC, ETG.SORT_SEQ ASC, ETG.GOODS_ID ASC

mapper.insert:
/* ExhibitionMapper.insertExhibitionBase: 기획전 기본 정보 등록 */
INSERT INTO EXHIBITION_BASE (
       EXHIBITION_NM
     , DISP_START_DT
     , DISP_END_DT
     , LIST_VIEW_YN
     , VIEW_YN
     , EXHIBITION_PC_DESC
     , EXHIBITION_MO_DESC
     , DEL_YN
     , REG_NO
     , UDT_NO
) VALUES (
       #{exhibitionNm}
     , NULLIF(#{dispStartDt}, '')
     , NULLIF(#{dispEndDt}, '')
     , #{listShowYn}
     , #{showYn}
     , #{exhibitionPcDesc}
     , #{exhibitionMoDesc}
     , 'N'
     , #{regNo}
     , #{udtNo}
)

mapper.update:
/* ExhibitionMapper.updateExhibitionBase: 기획전 기본 정보 수정 */
UPDATE EXHIBITION_BASE
   SET EXHIBITION_NM = #{exhibitionNm}
     , DISP_START_DT = NULLIF(#{dispStartDt}, '')
     , DISP_END_DT = NULLIF(#{dispEndDt}, '')
     , LIST_VIEW_YN = #{listShowYn}
     , VIEW_YN = #{showYn}
     , EXHIBITION_PC_DESC = #{exhibitionPcDesc}
     , EXHIBITION_MO_DESC = #{exhibitionMoDesc}
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE EXHIBITION_NO = #{exhibitionNo}
   AND DEL_YN = 'N'

/* ExhibitionMapper.updateExhibitionThumbnail: 기획전 썸네일 경로 업데이트 */
UPDATE EXHIBITION_BASE
   SET THUMBNAIL_URL = #{thumbnailUrl}
 WHERE EXHIBITION_NO = #{exhibitionNo}
   AND DEL_YN = 'N'

mapper.select:
/* ExhibitionMapper.countExhibitionByNo: 기획전 존재 여부 조회 */
SELECT COUNT(1)
  FROM EXHIBITION_BASE EB
 WHERE EB.EXHIBITION_NO = #{exhibitionNo}
   AND EB.DEL_YN = 'N'

/* ExhibitionMapper.countExhibitionTabByNo: 기획전 탭 수 조회 */
SELECT COUNT(1)
  FROM EXHIBITION_TAB ET
 WHERE ET.EXHIBITION_NO = #{exhibitionNo}
   AND ET.DEL_YN = 'N'

mapper.update:
/* ExhibitionMapper.updateExhibitionBaseDelete: 기획전 삭제 상태 변경 */
UPDATE EXHIBITION_BASE
   SET DEL_YN = 'Y'
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE EXHIBITION_NO = #{exhibitionNo}
   AND DEL_YN = 'N'

mapper.delete:
/* ExhibitionMapper.deleteExhibitionTabByExhibitionNo: 기획전 탭 일괄 삭제 */
DELETE
  FROM EXHIBITION_TAB
 WHERE EXHIBITION_NO = #{exhibitionNo}

/* ExhibitionMapper.deleteExhibitionTabByTabNo: 기획전 탭 단건 삭제 */
DELETE
  FROM EXHIBITION_TAB
 WHERE EXHIBITION_TAB_NO = #{exhibitionTabNo}

/* ExhibitionMapper.deleteExhibitionGoodsByExhibitionNo: 기획전 탭 상품 일괄 삭제 */
DELETE ETG
  FROM EXHIBITION_TAB_GOODS ETG
  JOIN EXHIBITION_TAB ET
    ON ET.EXHIBITION_TAB_NO = ETG.EXHIBITION_TAB_NO
 WHERE ET.EXHIBITION_NO = #{exhibitionNo}

mapper.select:
/* ExhibitionMapper.countExhibitionGoodsByTabNoList: 탭 번호 목록의 상품 건수 조회 */
SELECT COUNT(1)
  FROM EXHIBITION_TAB_GOODS
 WHERE EXHIBITION_TAB_NO IN

	#{tabNo}

mapper.delete:
/* ExhibitionMapper.deleteExhibitionGoodsByTabNoList: 탭 번호 목록의 상품 일괄 삭제 */
DELETE
  FROM EXHIBITION_TAB_GOODS
 WHERE EXHIBITION_TAB_NO IN

	#{tabNo}

mapper.insert:
/* ExhibitionMapper.insertExhibitionTab: 기획전 탭 등록 */
INSERT INTO EXHIBITION_TAB (
       EXHIBITION_NO
     , EXHIBITION_TAB_NM
     , DISP_START_DT
     , DISP_END_DT
     , VIEW_YN
     , DEL_YN
     , REG_NO
     , UDT_NO
) VALUES (
       #{exhibitionNo}
     , #{tabNm}
     , COALESCE(NULLIF(#{dispStartDt}, ''), NOW())
     , COALESCE(NULLIF(#{dispEndDt}, ''), NOW())
     , #{showYn}
     , 'N'
     , #{regNo}
     , #{udtNo}
)

mapper.update:
/* ExhibitionMapper.updateExhibitionTab: 기획전 탭 수정 */
UPDATE EXHIBITION_TAB
   SET EXHIBITION_TAB_NM = #{tabNm}
     , DISP_START_DT = COALESCE(NULLIF(#{dispStartDt}, ''), NOW())
     , DISP_END_DT = COALESCE(NULLIF(#{dispEndDt}, ''), NOW())
     , VIEW_YN = #{showYn}
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE EXHIBITION_TAB_NO = #{exhibitionTabNo}
   AND EXHIBITION_NO = #{exhibitionNo}

mapper.insert:
/* ExhibitionMapper.insertExhibitionGoods: 기획전 탭 상품 등록 */
INSERT INTO EXHIBITION_TAB_GOODS (
       EXHIBITION_TAB_NO
     , GOODS_ID
     , SORT_SEQ
     , VIEW_YN
     , REG_NO
     , UDT_NO
) VALUES (
       #{exhibitionTabNo}
     , #{goodsId}
     , #{dispOrd}
     , #{showYn}
     , #{regNo}
     , #{udtNo}
)
